            } else {
                left[i][j] = 1;
            }
        }
    }

    vector<vector<int>> right(n, vector<int>(m, 1));
    for (int i = 0; i < n; ++i) {
        for (int j = m - 2; j >= 0; --j) {
            if (grid[i][j] == grid[i][j + 1]) {
                right[i][j] = right[i][j + 1] + 1;
            } else {
                right[i][j] = 1;
            }
        }
    }

