#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;
const int MAXN = 2e5 + 5;
const int MAXA = 2e5 + 5;
using ll = long long;

ll inv6;

ll mod_pow(ll a, ll b) {
    ll res = 1;
    while (b > 0) {
        if (b % 2 == 1) res = res * a % MOD;
        a = a * a % MOD;
        b /= 2;
    }
    return res;
}

ll comb3(ll n) {
    if (n < 3) return 0;
    n %= MOD;
    return n * (n - 1) % MOD * (n - 2) % MOD * inv6 % MOD;
}

struct LCA {
    vector<int> depth;
    vector<vector<int>> up;
    vector<vector<int>> adj;
    int LOG;

    LCA(int n, const vector<vector<int>>& adj) : adj(adj) {
        LOG = ceil(log2(n)) + 1;
        depth.resize(n + 1);
        up.resize(n + 1, vector<int>(LOG));
        dfs(1, 0);
    }

    void dfs(int u, int parent) {
        up[u][0] = parent;
        for (int i = 1; i < LOG; ++i)
            up[u][i] = up[up[u][i-1]][i-1];
        for (int v : adj[u]) {
            if (v != parent) {
                depth[v] = depth[u] + 1;
                dfs(v, u);
            }
        }
    }

    int lca(int u, int v) {
        if (depth[u] < depth[v]) swap(u, v);
        int diff = depth[u] - depth[v];
        for (int i = 0; i < LOG; ++i)
            if (diff & (1 << i))
                u = up[u][i];
        if (u == v) return u;
        for (int i = LOG - 1; i >= 0; --i) {
            if (up[u][i] != up[v][i]) {
                u = up[u][i];
                v = up[v][i];
            }
        }
        return up[u][0];
    }
};

int spf[MAXA];
void sieve() {
    iota(spf, spf + MAXA, 0);
    for (int i = 2; i < MAXA; ++i) {
        if (spf[i] == i) {
            for (int j = i; j < MAXA; j += i)
                if (spf[j] == j)
                    spf[j] = i;
        }
    }
}

vector<int> get_primes(int x) {
    vector<int> primes;
    if (x == 1) return primes;
    while (x != 1) {
        int p = spf[x];
        primes.push_back(p);
        while (x % p == 0)
            x /= p;
    }
    return primes;
}

